type EventHandler<T = unknown> = (payload: T) => void | Promise<void>;

interface Subscription {
  id: string;
  event: string;
  handler: EventHandler;
  once: boolean;
  priority: number;
}

export class EventBus {
  private subscriptions: Map<string, Subscription[]> = new Map();
  private nextId = 0;
  private history: Array<{ event: string; payload: unknown; timestamp: number }> = [];
  private readonly maxHistory: number;

  constructor(maxHistory = 100) {
    this.maxHistory = maxHistory;
  }

  on<T>(event: string, handler: EventHandler<T>, priority = 0): string {
    const id = `sub_${this.nextId++}`;
    const subscription: Subscription = {
      id,
      event,
      handler: handler as EventHandler,
      once: false,
      priority,
    };

    const existing = this.subscriptions.get(event) ?? [];
    existing.push(subscription);
    existing.sort((a, b) => b.priority - a.priority);
    this.subscriptions.set(event, existing);

    return id;
  }

  once<T>(event: string, handler: EventHandler<T>, priority = 0): string {
    const id = `sub_${this.nextId++}`;
    const subscription: Subscription = {
      id,
      event,
      handler: handler as EventHandler,
      once: true,
      priority,
    };

    const existing = this.subscriptions.get(event) ?? [];
    existing.push(subscription);
    existing.sort((a, b) => b.priority - a.priority);
    this.subscriptions.set(event, existing);

    return id;
  }

  off(subscriptionId: string): boolean {
    for (const [event, subs] of this.subscriptions) {
      const index = subs.findIndex((s) => s.id === subscriptionId);
      if (index !== -1) {
        subs.splice(index, 1);
        if (subs.length === 0) {
          this.subscriptions.delete(event);
        }
        return true;
      }
    }
    return false;
  }

  async emit<T>(event: string, payload: T): Promise<void> {
    this.history.push({ event, payload, timestamp: Date.now() });
    if (this.history.length > this.maxHistory) {
      this.history.shift();
    }

    const subs = this.subscriptions.get(event);
    if (!subs || subs.length === 0) return;

    const toRemove: string[] = [];

    for (const sub of subs) {
      try {
        await sub.handler(payload);
      } catch (error) {
        console.error(`Error in handler ${sub.id} for event ${event}:`, error);
      }

      if (sub.once) {
        toRemove.push(sub.id);
      }
    }

    for (const id of toRemove) {
      this.off(id);
    }
  }

  removeAllListeners(event?: string): void {
    if (event) {
      this.subscriptions.delete(event);
    } else {
      this.subscriptions.clear();
    }
  }

  listenerCount(event: string): number {
    return this.subscriptions.get(event)?.length ?? 0;
  }

  eventNames(): string[] {
    return Array.from(this.subscriptions.keys());
  }

  getHistory(event?: string): Array<{ event: string; payload: unknown; timestamp: number }> {
    if (event) {
      return this.history.filter((h) => h.event === event);
    }
    return [...this.history];
  }

  clearHistory(): void {
    this.history = [];

type MessageCallback<T = unknown> = (data: T) => void | Promise<void>;

interface Registration {
  uid: string;
  channel: string;
  callback: MessageCallback;
  singleUse: boolean;
  weight: number;
}

export class MessageBroker {
  private registrations: Map<string, Registration[]> = new Map();
  private counter = 0;
  private log: Array<{ channel: string; data: unknown; time: number }> = [];
  private readonly maxLogSize: number;

  constructor(maxLogSize = 100) {
    this.maxLogSize = maxLogSize;
  }

  subscribe<T>(channel: string, callback: MessageCallback<T>, weight = 0): string {
    const uid = `reg_${this.counter++}`;
    const registration: Registration = {
      uid,
      channel,
      callback: callback as MessageCallback,
      singleUse: false,
      weight,
    };

    const current = this.registrations.get(channel) ?? [];
    current.push(registration);
    current.sort((a, b) => b.weight - a.weight);
    this.registrations.set(channel, current);

    return uid;
  }

  subscribeOnce<T>(channel: string, callback: MessageCallback<T>, weight = 0): string {
    const uid = `reg_${this.counter++}`;
    const registration: Registration = {
      uid,
      channel,
      callback: callback as MessageCallback,
      singleUse: true,
      weight,
    };

    const current = this.registrations.get(channel) ?? [];
    current.push(registration);
    current.sort((a, b) => b.weight - a.weight);
    this.registrations.set(channel, current);

    return uid;
  }

  unsubscribe(registrationUid: string): boolean {
    for (const [channel, regs] of this.registrations) {
      const idx = regs.findIndex((r) => r.uid === registrationUid);
      if (idx !== -1) {
        regs.splice(idx, 1);
        if (regs.length === 0) {
          this.registrations.delete(channel);
        }
        return true;
      }
    }
    return false;
  }

  async publish<T>(channel: string, data: T): Promise<void> {
    this.log.push({ channel, data, time: Date.now() });
    if (this.log.length > this.maxLogSize) {
      this.log.shift();
    }

    const regs = this.registrations.get(channel);
    if (!regs || regs.length === 0) return;

    const expired: string[] = [];

    for (const reg of regs) {
      try {
        await reg.callback(data);
      } catch (err) {
        console.error(`Error in callback ${reg.uid} for channel ${channel}:`, err);
      }

      if (reg.singleUse) {
        expired.push(reg.uid);
      }
    }

    for (const uid of expired) {
      this.unsubscribe(uid);
    }
  }

  removeAllCallbacks(channel?: string): void {
    if (channel) {
      this.registrations.delete(channel);
    } else {
      this.registrations.clear();
    }
  }

  callbackCount(channel: string): number {
    return this.registrations.get(channel)?.length ?? 0;
  }

  channelNames(): string[] {
    return Array.from(this.registrations.keys());
  }

  getLog(channel?: string): Array<{ channel: string; data: unknown; time: number }> {
    if (channel) {
      return this.log.filter((entry) => entry.channel === channel);
    }
    return [...this.log];
  }

  clearLog(): void {
    this.log = [];

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
  createdAt: number;
  accessCount: number;
}

interface CacheStats {
  hits: number;
  misses: number;
  evictions: number;
  size: number;
}

export class LRUCache<T> {
  private cache = new Map<string, CacheEntry<T>>();
  private readonly maxSize: number;
  private readonly defaultTTL: number;
  private stats: CacheStats = { hits: 0, misses: 0, evictions: 0, size: 0 };

  constructor(maxSize = 500, defaultTTL = 300000) {
    this.maxSize = maxSize;
    this.defaultTTL = defaultTTL;
  }

  get(key: string): T | undefined {
    const entry = this.cache.get(key);
    if (!entry) {
      this.stats.misses++;
      return undefined;
    }

    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      this.stats.misses++;
      this.stats.size--;
      return undefined;
    }

    // Move to end (most recently used)
    this.cache.delete(key);
    entry.accessCount++;
    this.cache.set(key, entry);
    this.stats.hits++;
    return entry.value;
  }

  set(key: string, value: T, ttl?: number): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.maxSize) {
      this.evictOldest();
    }

    const entry: CacheEntry<T> = {
      value,
      expiresAt: Date.now() + (ttl ?? this.defaultTTL),
      createdAt: Date.now(),
      accessCount: 0,
    };

    this.cache.set(key, entry);
    this.stats.size = this.cache.size;
  }

  delete(key: string): boolean {
    const deleted = this.cache.delete(key);
    if (deleted) {
      this.stats.size = this.cache.size;
    }
    return deleted;
  }

  clear(): void {
    this.cache.clear();
    this.stats.size = 0;
  }

  has(key: string): boolean {
    const entry = this.cache.get(key);
    if (!entry) return false;
    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      this.stats.size--;
      return false;
    }
    return true;
  }

  private evictOldest(): void {
    const firstKey = this.cache.keys().next().value;
    if (firstKey !== undefined) {
      this.cache.delete(firstKey);
      this.stats.evictions++;
      this.stats.size--;
    }
  }

  getStats(): CacheStats {
    return { ...this.stats };
  }

  prune(): number {
    let pruned = 0;
    const now = Date.now();
    for (const [key, entry] of this.cache) {
      if (now > entry.expiresAt) {
        this.cache.delete(key);
        pruned++;
      }
    }
    this.stats.size = this.cache.size;
    return pruned;
  }

  keys(): string[] {
    return Array.from(this.cache.keys());
  }

  values(): T[] {
